msg.topic = 'weather';
msg.parts = { id: 'Tagesinfo' };
msg.weather = msg.payload;
return msg;

msg.topic = 'calendar';
msg.calendar = msg.payload;
msg.parts = { id: 'Tagesinfo' };
return msg;

let now = new Date();
let weather = msg.payload.weather;
let calendar = msg.payload.calendar;

function dayToText(day) {
    const days = {
        1: 'erster', 2: 'zweiter', 3: 'dritter', 4: 'vierter', 5: 'fünfter',
        6: 'sechster', 7: 'siebter', 8: 'achter', 9: 'neunter', 10: 'zehnter',
        11: 'elfter', 12: 'zwölfter', 13: 'dreizehnter', 14: 'vierzehnter', 15: 'fünfzehnter',
        16: 'sechzehnter', 17: 'siebzehnter', 18: 'achtzehnter', 19: 'neunzehnter', 20: 'zwanzigster',
        21: 'einundzwanzigster', 22: 'zweiundzwanzigster', 23: 'dreiundzwanzigster', 24: 'vierundzwanzigster',
        25: 'fünfundzwanzigster', 26: 'sechsundzwanzigster', 27: 'siebenundzwanzigster', 28: 'achtundzwanzigster',
        29: 'neunundzwanzigster', 30: 'dreißigster', 31: 'einunddreißigster'
    };
    return days[day] || day;
}

let tempRaw = weather?.current_weather?.temperature ?? null;
let temp = tempRaw !== null ? Math.round(tempRaw) : null;
let weatherCode = weather?.current_weather?.weathercode ?? -1;
let event = calendar?.attributes?.message ?? 'keine Termine';

let time = now.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });
let weekday = now.toLocaleDateString('de-DE', { weekday: 'long' });
let month = now.toLocaleDateString('de-DE', { month: 'long' });
let year = now.getFullYear();
let spokenDay = dayToText(now.getDate());
let date = `${weekday}, der ${spokenDay} ${month} ${year}`;

let hour = now.getHours();
let greeting = 'Hallo';

if (hour < 12) {
    greeting = 'Guten Morgen';
} else if (hour < 18) {
    greeting = 'Guten Tag';
} else {
    greeting = 'Guten Abend';
}

let weatherDescription = 'wechselhaftem Wetter';

switch (weatherCode) {
    case 0:
        weatherDescription = 'klarem Himmel';
        break;
    case 1:
    case 2:
    case 3:
        weatherDescription = 'leicht bewölktem Himmel';
        break;
    case 45:
    case 48:
        weatherDescription = 'nebligem Wetter';
        break;
    case 51:
    case 53:
    case 55:
        weatherDescription = 'leichtem Regen';
        break;
    case 61:
    case 63:
    case 65:
        weatherDescription = 'regnerischem Wetter';
        break;
    case 71:
    case 73:
    case 75:
        weatherDescription = 'Schneefall';
        break;
    case 80:
    case 81:
    case 82:
        weatherDescription = 'Regenschauern';
        break;
    case 95:
        weatherDescription = 'Gewitter';
        break;
}

let weatherText = 'Ich konnte das Wetter momentan nicht abrufen.';
if (temp !== null) {
    weatherText = `Draußen sind es aktuell ${temp} Grad bei ${weatherDescription}.`;
}

let eventText = '';
if (event === 'keine Termine') {
    eventText = 'Du hast aktuell keine anstehenden Termine.';
} else {
    eventText = `Dein nächster Termin ist ${event}.`;
}

let message =
    `${greeting}. ` +
    `Heute ist ${date}. ` +
    `Die aktuelle Uhrzeit ist ${time}. ` +
    `${weatherText} ` +
    `${eventText}`;

msg.payload = {
    message: message,
    title: 'Jarvis Tagesinfo',
    data: {
        tts_text: message
    }
};

return msg;

msg.payload = {
    success: true,
    intent: 'dailyInfo',
    entity: 'jarvis.daily_info',
    state: 'executed',
    message: msg.payload.message,
    audioUrl: null,
    ttsProfile: 'jarvis'
};

return msg;
